import numpy as npimport scipydef calculate_mean(D):    m= np.mean(D,axis=1)    return np.array(m).reshape(4,1)def covar_mat(D):    mean = calculate_mean(D)    DCent = D - mean    return (DCent @ DCent.T)/float(D.shape[1])def pca_compute(D,m):    covar = covar_mat(D)    U, s, Vh = np.linalg.svd(covar)    P = U[:,0:m]    return Pdef pca_apply(P,d):    return P.T @ ddef compute_lda_geig(D,L,m):    sb,sw = sbsw_compute(D, L)    s,U = scipy.linalg.eigh(sb,sw)    return U[:, ::-1][:,0:m]def lda_apply(D,U):    return U.T @ Ddef sbsw_compute(D,L):    Sb = 0    Sw = 0    globmean = calculate_mean(D)    for i in np.unique(L):        DClass = D[:,L==i]        meanclass = calculate_mean(DClass)        Sb += (meanclass-globmean)@(meanclass-globmean).T*DClass.shape[1]        Sw += (DClass-meanclass)@(DClass-meanclass).T    return Sb/D.shape[1] , Sw/D.shape[1]